from pathlib import Path
from datetime import date, datetime, timedelta
import csv
import re

LOG_DIR = Path('/app/logs')
OUT = Path('/app/summary.csv')
REF = date(2025, 8, 12)
SEVERITIES = ('ERROR', 'WARNING', 'INFO')
PERIODS = ('today', 'last_7_days', 'last_30_days', 'month_to_date', 'total')
counts = {p: {s: 0 for s in SEVERITIES} for p in PERIODS}
pat = re.compile(r'\[(ERROR|WARNING|INFO)\]')

for path in sorted(LOG_DIR.glob('*.log')):
    try:
        file_date = datetime.strptime(path.name[:10], '%Y-%m-%d').date()
    except ValueError:
        continue
    membership = ['total']
    if file_date == REF:
        membership.append('today')
    if REF - timedelta(days=6) <= file_date <= REF:
        membership.append('last_7_days')
    if REF - timedelta(days=29) <= file_date <= REF:
        membership.append('last_30_days')
    if file_date.year == REF.year and file_date.month == REF.month and file_date.day <= REF.day:
        membership.append('month_to_date')

    with path.open() as f:
        for line in f:
            m = pat.search(line)
            if not m:
                continue
            sev = m.group(1)
            for period in membership:
                counts[period][sev] += 1

with OUT.open('w', newline='') as f:
    w = csv.writer(f)
    w.writerow(['period', 'severity', 'count'])
    for period in PERIODS:
        for sev in SEVERITIES:
            w.writerow([period, sev, counts[period][sev]])
